import SwiftUI
import AIUsagesTrackersLib

/// Scrollable popover anchored to the menu bar item; uses LazyVStack + maxHeight
/// so the popover does not stretch unboundedly when many accounts are present.
struct UsageDetailsView: View {
    let store: UsageStore
    let refreshState: RefreshState
    let historyReader: UsageHistoryReader
    let updateState: UpdateState
    let onRefresh: () async -> Void
    let onOpenSettings: () -> Void
    let onQuit: () -> Void
    let onInstallUpdate: () -> Void
    let onSkipUpdate: () -> Void
    let onLaterUpdate: () -> Void

    @State private var contentMode: PopoverContentMode = .list
    @State private var selectedHistoryWindow: UsageHistoryTimeWindow = .twentyFourHours
    @State private var historySnapshot: UsageHistorySnapshot = .empty
    @State private var historyReferenceDate = Date()
    @State private var historyWindowOffset: Int = 0
    @State private var isLoadingHistory = false

    private static let popoverWidth: CGFloat = 320
    private static let maxScreenHeightRatio: CGFloat = 0.9
    private static let fallbackScreenHeight: CGFloat = 800
    private static let historyAutoRefreshInterval: Duration = .seconds(60)
    /// Reserved for header + footer + dividers so the full popover stays within the ratio cap.
    private static let chromeHeightReserve: CGFloat = 80
    private static let sponsorURL = URL(string: "https://github.com/sponsors/fcamblor")!

    private var maxScrollHeight: CGFloat {
        let screenHeight = NSScreen.main?.visibleFrame.height ?? Self.fallbackScreenHeight
        return screenHeight * Self.maxScreenHeightRatio - Self.chromeHeightReserve
    }

    var body: some View {
        VStack(spacing: 0) {
            header

            Divider()

            if let pending = updateState.pendingUpdate {
                UpdateAvailableBanner(
                    update: pending,
                    installationKind: updateState.installationKind,
                    isInstalling: updateState.phase == .installing,
                    onInstall: onInstallUpdate,
                    onSkip: onSkipUpdate,
                    onLater: onLaterUpdate
                )
                .padding(.horizontal, 12)
                .padding(.vertical, 8)
                Divider()
            }

            content

            Divider()

            footer
        }
        .frame(width: Self.popoverWidth)
        .task(id: historyTaskID) {
            await runHistoryRefreshLoopIfNeeded()
        }
    }

    private var historyTaskID: String {
        "\(contentMode.rawValue)-\(selectedHistoryWindow.rawValue)"
    }

    /// Returns a map of vendor → first index in sorted, for vendors that have active outages.
    private func vendorsNeedingBanner(in sorted: [VendorUsageEntry]) -> [Vendor: Int] {
        var result: [Vendor: Int] = [:]
        for (index, entry) in sorted.enumerated() where result[entry.vendor] == nil {
            if store.outagesByVendor[entry.vendor] != nil {
                result[entry.vendor] = index
            }
        }
        return result
    }

    // MARK: - Subviews

    @ViewBuilder
    private var content: some View {
        switch contentMode {
        case .list:
            listingContent
        case .chart:
            chartContent
        }
    }

    @ViewBuilder
    private var listingContent: some View {
        let prefs = AppDelegate.sharedPreferences
        let sorted = store.entries
            .excluding(ignoredAccounts: prefs.ignoredAccounts)
            .sortedForDisplay()
        if sorted.isEmpty && !store.entries.isEmpty {
            allAccountsIgnoredState
        } else if sorted.isEmpty {
            emptyState
        } else {
            ScrollView {
                LazyVStack(spacing: 8) {
                    // Track which vendors have already shown their status banner
                    // using a running cursor — entries are sorted by vendor so
                    // entries of the same vendor are contiguous.
                    let vendorsWithBanner = vendorsNeedingBanner(in: sorted)
                    ForEach(Array(sorted.enumerated()), id: \.element.id) { index, entry in
                        if vendorsWithBanner[entry.vendor] == index,
                           let outages = store.outagesByVendor[entry.vendor] {
                            VendorStatusBanner(outages: outages)
                        }
                        AccountCardView(
                            entry: entry,
                            isRefreshing: refreshState.isRefreshing(
                                vendor: entry.vendor,
                                account: entry.account
                            ),
                            onIgnore: {
                                let ignored = IgnoredAccount(vendor: entry.vendor, account: entry.account)
                                if !prefs.ignoredAccounts.contains(ignored) {
                                    prefs.ignoredAccounts.append(ignored)
                                }
                            }
                        )
                    }
                }
                .padding(12)
            }
            .frame(maxHeight: maxScrollHeight)
            .background(Color(NSColor.windowBackgroundColor).opacity(0.4))
        }
    }

    private var chartContent: some View {
        ScrollView {
            UsageHistoryChartView(
                snapshot: historySnapshot,
                referenceDate: historyReferenceDate,
                selectedWindow: historyWindowBinding,
                isLoading: isLoadingHistory,
                configurations: AppDelegate.sharedPreferences.chartConfigurations,
                currentEntries: store.entries,
                onPreviousWindow: {
                    Task { await moveHistoryWindow(direction: .previous) }
                },
                onNextWindow: {
                    Task { await moveHistoryWindow(direction: .next) }
                }
            )
        }
        .frame(maxHeight: maxScrollHeight)
        .background(Color(NSColor.windowBackgroundColor).opacity(0.4))
    }

    private var historyWindowBinding: Binding<UsageHistoryTimeWindow> {
        Binding(
            get: { selectedHistoryWindow },
            set: { newValue in
                selectedHistoryWindow = newValue
                historyWindowOffset = 0
            }
        )
    }

    private var header: some View {
        let refreshing = !refreshState.inFlight.isEmpty
        return HStack(spacing: 8) {
            Button {
                onOpenSettings()
            } label: {
                Image(systemName: "gearshape")
                    .frame(width: 16, height: 16)
                    .hoverAffordance()
            }
            .buttonStyle(.borderless)
            .controlSize(.small)
            .help("Settings")
            .keyboardShortcut(",", modifiers: .command)
            .focusable(false)

            Spacer()

            Text("AI Usages Tracker")
                .font(.system(size: 11, weight: .medium))
                .foregroundStyle(.secondary)

            Spacer()

            Button {
                guard !refreshing else { return }
                Task { await onRefresh() }
            } label: {
                ZStack {
                    if refreshing {
                        ProgressView()
                            .controlSize(.small)
                            .scaleEffect(0.6)
                    } else {
                        Image(systemName: "arrow.clockwise")
                    }
                }
                .frame(width: 16, height: 16)
                .hoverAffordance(isEnabled: !refreshing)
            }
            .buttonStyle(.borderless)
            .controlSize(.small)
            .disabled(refreshing)
            .help("Refresh usage data")
            .keyboardShortcut("r")
            .focusable(false)
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 8)
    }

    private var allAccountsIgnoredState: some View {
        VStack(spacing: 8) {
            Text("All accounts are hidden")
                .font(.system(size: 12, weight: .medium))
                .foregroundStyle(.secondary)
            Text("Remove ignored accounts in Settings to restore visibility.")
                .font(.system(size: 11))
                .foregroundStyle(.tertiary)
                .multilineTextAlignment(.center)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 32)
        .padding(.horizontal, 24)
    }

    @ViewBuilder
    private var emptyState: some View {
        if AppDelegate.sharedPreferences.menuBarSegments.isEmpty {
            unconfiguredEmptyState
        } else {
            VStack(spacing: 8) {
                Text("No usage data")
                    .font(.system(size: 12, weight: .medium))
                    .foregroundStyle(.secondary)
                Text("Waiting for data...")
                    .font(.system(size: 11))
                    .foregroundStyle(.tertiary)
            }
            .frame(maxWidth: .infinity)
            .padding(.vertical, 32)
        }
    }

    private var unconfiguredEmptyState: some View {
        VStack(spacing: 12) {
            Image(systemName: "gearshape.2")
                .font(.system(size: 28, weight: .light))
                .foregroundStyle(.secondary)
            Text("No menu bar segment yet")
                .font(.system(size: 12, weight: .medium))
                .foregroundStyle(.primary)
            Text("Add your first segment to start tracking your AI usages directly from the menu bar.")
                .font(.system(size: 11))
                .foregroundStyle(.secondary)
                .multilineTextAlignment(.center)
                .fixedSize(horizontal: false, vertical: true)
            Button {
                onOpenSettings()
            } label: {
                Text("Open Settings")
            }
            .controlSize(.small)
        }
        .frame(maxWidth: .infinity)
        .padding(.horizontal, 24)
        .padding(.vertical, 24)
    }

    private var footer: some View {
        HStack {
            Picker("Popover content", selection: $contentMode) {
                Image(systemName: "list.bullet")
                    .tag(PopoverContentMode.list)
                Image(systemName: "chart.xyaxis.line")
                    .tag(PopoverContentMode.chart)
            }
            .pickerStyle(.segmented)
            .labelsHidden()
            .controlSize(.mini)
            .frame(width: 62)
            .help("Switch between usage list and history chart")
            .focusable(false)

            Spacer()

            Button {
                NSWorkspace.shared.open(Self.sponsorURL)
            } label: {
                HStack(spacing: 4) {
                    Image(systemName: "heart.fill")
                        .font(.system(size: 11))
                        .foregroundStyle(.pink)
                    Text("Support")
                        .font(.system(size: 11))
                }
                .hoverAffordance()
            }
            .buttonStyle(.borderless)
            .controlSize(.small)
            .help("Like the app ? You can buy me a coffee")
            .focusable(false)

            Button {
                onQuit()
            } label: {
                Text("Quit")
                    .hoverAffordance()
            }
            .buttonStyle(.borderless)
            .keyboardShortcut("q")
            .controlSize(.small)
            .focusable(false)
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 8)
    }

    @MainActor
    private func runHistoryRefreshLoopIfNeeded() async {
        guard contentMode == .chart else { return }
        while !Task.isCancelled {
            await loadHistory()
            do {
                try await Task.sleep(for: Self.historyAutoRefreshInterval)
            } catch {
                break
            }
        }
    }

    private func computeReferenceDate() -> Date {
        guard historyWindowOffset > 0,
              let interval = selectedHistoryWindow.timeInterval else {
            return Date()
        }
        return Date().addingTimeInterval(-Double(historyWindowOffset) * interval)
    }

    @MainActor
    private func loadHistory() async {
        let requestedWindow = selectedHistoryWindow
        let requestedOffset = historyWindowOffset
        let requestedDate = computeReferenceDate()
        isLoadingHistory = true
        let snapshot = await historyReader.load(window: requestedWindow, now: requestedDate)
        guard contentMode == .chart,
              selectedHistoryWindow == requestedWindow,
              historyWindowOffset == requestedOffset else {
            isLoadingHistory = false
            return
        }
        historySnapshot = snapshot
        historyReferenceDate = requestedDate
        isLoadingHistory = false
    }

    @MainActor
    private func moveHistoryWindow(direction: HistoryWindowDirection) async {
        guard selectedHistoryWindow.timeInterval != nil else { return }
        switch direction {
        case .previous:
            historyWindowOffset += 1
        case .next:
            guard historyWindowOffset > 0 else { return }
            historyWindowOffset -= 1
        }
        await loadHistory()
    }
}

private enum PopoverContentMode: String, Hashable {
    case list
    case chart
}

private enum HistoryWindowDirection {
    case previous
    case next
}

