4	
5	struct EventuallyTimeoutError: Error, CustomStringConvertible {
6	    let timeout: TimeInterval
7	    var description: String { "Condition not met within \(timeout)s" }
8	}
9	
10	/// Polls `condition` on the main actor at `interval` until it returns true or `timeout` expires.
11	@MainActor
12	func eventually(
13	    timeout: TimeInterval = 2.0,
14	    interval: TimeInterval = 0.01,
15	    _ condition: @MainActor () -> Bool
16	) async throws {
17	    let deadline = Date(timeIntervalSinceNow: timeout)
18	    while true {
19	        if condition() { return }
20	        guard Date() < deadline else { throw EventuallyTimeoutError(timeout: timeout) }
21	        try await Task.sleep(for: .seconds(interval))
22	    }
23	}
24	
25	/// Non-isolated overload for tests that need `await` inside the condition
26	/// (e.g. reading actor-isolated properties).
27	func eventually(
28	    timeout: TimeInterval = 2.0,
29	    interval: TimeInterval = 0.01,
30	    _ condition: @escaping @Sendable () async -> Bool
31	) async throws {
32	    let deadline = Date(timeIntervalSinceNow: timeout)
33	    while true {
34	        if await condition() { return }
35	        guard Date() < deadline else { throw EventuallyTimeoutError(timeout: timeout) }
36	        try await Task.sleep(for: .seconds(interval))
37	    }
38	}
39	
